size_t cPersistedDiplomacyEventFactory::GetTypes(uint32_t* pDstTypes, size_t count) const {
	if (count >= 1) {
		pDstTypes[0] = cPersistedDiplomacyEvent::NOUN_ID;
		return 1;
	}
	return 0;
}
Object* cPersistedDiplomacyEventFactory::Create(uint32_t type, ICoreAllocator* pAllocator) {
	return new cPersistedDiplomacyEvent();
}
const char* cPersistedDiplomacyEventFactory::GetName(uint32_t type) const {
	return "cPersistedDiplomacyEvent";
}

uint32_t cPersistedDiplomacyEvent::GetCastID() const {
	return TYPE;
}
uint32_t cPersistedDiplomacyEvent::GetNounID() const {
	return NOUN_ID;
}

void* cPersistedDiplomacyEvent::Cast(uint32_t type) const {
	CLASS_CAST(cPersistedDiplomacyEvent);
	PARENT_CAST(cPersistedEvent);
	return nullptr;
}

bool cPersistedDiplomacyEvent::Write(Simulator::ISerializerStream* stream)
{
	empire1ID = empire1->GetEmpireID();
	empire2ID = empire2->GetEmpireID();
	serializationEventType = uint32_t(eventType);
	return cPersistedEvent::Write(stream) && Simulator::ClassSerializer(this, ATTRIBUTES).Write(stream);
}
bool cPersistedDiplomacyEvent::Read(Simulator::ISerializerStream* stream)
{
	bool ret = cPersistedEvent::Read(stream) && Simulator::ClassSerializer(this, ATTRIBUTES).Read(stream);
	empire1 = StarManager.GetEmpire(empire1ID);
	empire2 = StarManager.GetEmpire(empire2ID);
	eventType = PersistedDiplomacyEventType(serializationEventType);
	return ret;
}

/// END OF AUTOGENERATED METHODS ///
