Simulator::Attribute cPersistedDiplomacyEvent::ATTRIBUTES[] = {

	SimAttribute(cPersistedDiplomacyEvent, empire1ID, 0),
	SimAttribute(cPersistedDiplomacyEvent, empire2ID, 1),
	SimAttribute(cPersistedDiplomacyEvent, serializationEventType, 2),
	Simulator::Attribute()
};

bool cPersistedDiplomacyEvent::Valid() {
	return cPersistedEvent::Valid() && EmpireUtils::ValidNpcEmpire(empire1.get(), true) && EmpireUtils::ValidNpcEmpire(empire2.get(), true);
}

cEmpire* cPersistedDiplomacyEvent::GetEmpire1() {
	return empire1.get();
}

void cPersistedDiplomacyEvent::SetEmpire1(cEmpire* empire1) {
	this->empire1 = empire1;
}

cEmpire* cPersistedDiplomacyEvent::GetEmpire2() {
	return empire2.get();
}

void cPersistedDiplomacyEvent::SetEmpire2(cEmpire* empire2) {
	this->empire2 = empire2;
}

PersistedDiplomacyEventType cPersistedDiplomacyEvent::GetEventType(){
	return eventType;
}

void cPersistedDiplomacyEvent::SetEventType(PersistedDiplomacyEventType eventType){
	this->eventType = eventType;
}
